query_schema:
query variantInfo($variantId: String!) {
  variant(variantId: $variantId) {
    id
    rsIds
    chromosome
    position
    referenceAllele
    alternateAllele
    hgvsId
    variantDescription
    mostSevereConsequence {
      id
      label
    }
    alleleFrequencies {
      populationName
      alleleFrequency
    }
  }
}

query variantCredibleSets($variantId: String!, $size: Int = 10, $index: Int = 0) {
  variant(variantId: $variantId) {
    id
    rsIds
    credibleSets(studyTypes: [gwas], page: {size: $size, index: $index}) {
      count
      rows {
        studyLocusId
        studyId
        region
        finemappingMethod
        pValueMantissa
        pValueExponent
        beta
        confidence
        study {
          id
          traitFromSource
          publicationFirstAuthor
          pubmedId
          diseases {
            id
            name
          }
        }
        l2GPredictions {
          rows {
            target {
              id
              approvedSymbol
            }
            score
          }
        }
      }
    }
  }
}

query searchStudies($diseaseIds: [String!], $enableIndirect: Boolean = true) {
  studies(diseaseIds: $diseaseIds, enableIndirect: $enableIndirect) {
    count
    rows {
      id
      traitFromSource
      studyType
      publicationFirstAuthor
      publicationDate
      nSamples
      diseases {
        id
        name
      }
    }
  }
}

query credibleSetDetail($studyLocusId: String!) {
  credibleSet(studyLocusId: $studyLocusId) {
    studyLocusId
    studyId
    region
    chromosome
    position
    finemappingMethod
    pValueMantissa
    pValueExponent
    beta
    standardError
    confidence
    credibleSetlog10BF
    sampleSize
    variant {
      id
      rsIds
      chromosome
      position
      referenceAllele
      alternateAllele
      mostSevereConsequence {
        id
        label
      }
    }
    study {
      id
      traitFromSource
      publicationFirstAuthor
      publicationTitle
      pubmedId
      nSamples
      diseases {
        id
        name
      }
    }
    l2GPredictions {
      rows {
        target {
          id
          approvedSymbol
        }
        score
      }
    }
  }
}

query studyCredibleSets($studyIds: [String!], $size: Int = 20, $index: Int = 0) {
  credibleSets(studyIds: $studyIds, studyTypes: [gwas], page: {size: $size, index: $index}) {
    count
    rows {
      studyLocusId
      studyId
      region
      chromosome
      position
      finemappingMethod
      pValueMantissa
      pValueExponent
      beta
      confidence
      variant {
        id
        rsIds
      }
      study {
        traitFromSource
        diseases {
          id
          name
        }
      }
      l2GPredictions {
        rows {
          target {
            id
            approvedSymbol
          }
          score
        }
      }
    }
  }
}

query variantEffectPredictions($variantId: String!) {
  variant(variantId: $variantId) {
    id
    rsIds
    variantEffect {
      method
      assessment
      assessmentFlag
      score
      normalisedScore
    }
  }
}

query variantTranscriptConsequences($variantId: String!) {
  variant(variantId: $variantId) {
    id
    rsIds
    transcriptConsequences {
      transcriptId
      target { id approvedSymbol }
      aminoAcidChange
      consequenceScore
      impact
      isEnsemblCanonical
      variantConsequences { id label }
    }
  }
}

query variantPharmacogenomics($variantId: String!) {
  variant(variantId: $variantId) {
    id
    rsIds
    pharmacogenomics {
      drugs { drugFromSource drugId }
      phenotypeText
      genotypeAnnotationText
      evidenceLevel
      pgxCategory
      phenotypeFromSourceId
      datasourceId
    }
  }
}

query credibleSetColocalisation($studyLocusId: String!, $size: Int = 20) {
  credibleSet(studyLocusId: $studyLocusId) {
    studyLocusId
    colocalisation(page: {size: $size, index: 0}) {
      count
      rows {
        colocalisationMethod
        h3
        h4
        clpp
        numberColocalisingVariants
        otherStudyLocus {
          studyLocusId
          studyType
          study { id traitFromSource }
        }
      }
    }
  }
}
